blocks.code:
@import url('https://fonts.googleapis.com/css2?family=IBM+Plex+Sans:wght@400;500;600&family=IBM+Plex+Serif:ital,wght@0,400;0,500;1,400;1,500&family=IBM+Plex+Mono:wght@400;500&display=swap');

.loom-app {
  --font-serif: "IBM Plex Serif", "Noto Serif", Georgia, serif;
  --font-sans:  "IBM Plex Sans", "Noto Sans", ui-sans-serif, system-ui, sans-serif;
  --font-mono:  "IBM Plex Mono", "Noto Sans Mono", ui-monospace, Menlo, monospace;

  --measure: 70ch;
  --measure-wide: 82ch;
  --col-left: 268px;
  --col-right: 240px;

  background: var(--bg-page);
  color: var(--fg-primary);
  font-family: var(--font-serif);
  font-feature-settings: "kern", "liga", "onum";
  text-rendering: optimizeLegibility;
  -webkit-font-smoothing: antialiased;
  transition: background-color 180ms ease, color 180ms ease;
  position: relative;
  min-height: 100%;
  height: 100%;
  display: flex;
  flex-direction: column;
  overflow: hidden;
}

.loom-app ::selection { background: var(--selection); }
.loom-app * { box-sizing: border-box; }
.loom-app a { color: inherit; text-decoration: none; }

.loom-theme-light {
  --bg-page:      #F2E5BC;
  --bg-surface:   #EBDBB2;
  --bg-code:      #ECDFB3;
  --bg-inline:    rgba(60, 56, 54, 0.06);
  --bg-callout:   #EBDBB2;
  --fg-primary:   #3C3836;
  --fg-secondary: #504945;
  --fg-tertiary:  #7C6F64;
  --border-hair:  rgba(60, 56, 54, 0.12);
  --border-soft:  rgba(60, 56, 54, 0.07);
  --border-strong:rgba(60, 56, 54, 0.20);
  --accent:       #B8553A;
  --accent-soft:  rgba(184, 85, 58, 0.12);
  --accent-ring:  rgba(184, 85, 58, 0.32);
  --accent-fg:    #FFFFFF;
  --success:      #79740E;
  --warning:      #B57614;
  --selection:    rgba(184, 85, 58, 0.20);
  --shadow-modal: 0 24px 60px -24px rgba(60, 56, 54, 0.24),
                  0 2px 6px rgba(60, 56, 54, 0.10);
}

.loom-theme-dark {
  --bg-page:      #0F1014;
  --bg-surface:   #15171D;
  --bg-code:      #1B1E26;
  --bg-inline:    rgba(255, 255, 255, 0.06);
  --bg-callout:   #1B1E26;
  --fg-primary:   #E6E6EA;
  --fg-secondary: #B6B8C2;
  --fg-tertiary:  #7A7E8C;
  --border-hair:  rgba(255, 255, 255, 0.07);
  --border-soft:  rgba(255, 255, 255, 0.04);
  --border-strong:rgba(255, 255, 255, 0.16);
  --accent:       #3E7DBF;
  --accent-soft:  rgba(62, 125, 191, 0.16);
  --accent-ring:  rgba(62, 125, 191, 0.45);
  --accent-fg:    #F5F8FC;
  --success:      #81B48C;
  --warning:      #DEC184;
  --selection:    rgba(62, 125, 191, 0.32);
  --shadow-modal: 0 24px 60px -20px rgba(0, 0, 0, 0.75),
                  0 2px 6px rgba(0, 0, 0, 0.4);
}

.loom-topbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 24px;
  padding: 0 24px;
  height: 52px;
  border-bottom: 1px solid var(--border-hair);
  font-family: var(--font-sans);
  font-size: 13px;
  color: var(--fg-secondary);
  flex-shrink: 0;
}
.loom-topbar-left { display: flex; align-items: center; gap: 12px; }
.loom-topbar-right { display: flex; align-items: center; gap: 10px; }

.loom-icon-btn {
  width: 28px; height: 28px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  background: transparent;
  border: 1px solid transparent;
  border-radius: 4px;
  color: var(--fg-secondary);
  cursor: pointer;
  transition: background-color 120ms ease, color 120ms ease;
}
.loom-icon-btn:hover { background: var(--bg-surface); color: var(--fg-primary); }

.loom-wordmark {
  display: inline-flex;
  align-items: baseline;
  gap: 8px;
  font-family: var(--font-sans);
  color: var(--fg-primary);
  letter-spacing: -0.005em;
}
.loom-wordmark-mark {
  font-family: var(--font-serif);
  font-style: italic;
  font-size: 18px;
  color: var(--accent);
  margin-right: -2px;
  line-height: 1;
}
.loom-wordmark-text { font-weight: 500; font-size: 14px; }
.loom-wordmark-ver {
  font-size: 11px;
  color: var(--fg-tertiary);
  font-variant-numeric: tabular-nums;
  padding: 1px 5px;
  border: 1px solid var(--border-hair);
  border-radius: 3px;
  font-weight: 400;
}

.loom-topnav { display: flex; align-items: center; gap: 2px; }
.loom-topnav-item {
  padding: 6px 10px;
  border-radius: 4px;
  color: var(--fg-secondary);
  font-weight: 400;
  transition: background-color 120ms ease, color 120ms ease;
}
.loom-topnav-item:hover { color: var(--fg-primary); }
.loom-topnav-active { color: var(--fg-primary); background: var(--bg-surface); }

.loom-search-trigger {
  display: inline-flex;
  align-items: center;
  justify-content: space-between;
  gap: 24px;
  min-width: 220px;
  padding: 5px 6px 5px 10px;
  background: var(--bg-surface);
  border: 1px solid var(--border-hair);
  border-radius: 5px;
  color: var(--fg-tertiary);
  font-family: var(--font-sans);
  font-size: 12.5px;
  cursor: pointer;
  transition: border-color 120ms ease;
}
.loom-search-trigger:hover { border-color: var(--border-strong); }
.loom-search-trigger kbd {
  font-family: var(--font-sans);
  font-size: 11px;
  padding: 2px 5px;
  border: 1px solid var(--border-hair);
  border-radius: 3px;
  color: var(--fg-secondary);
  background: var(--bg-page);
}

.loom-theme-toggle {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 3px 9px 3px 4px;
  border: 1px solid var(--border-hair);
  border-radius: 999px;
  background: transparent;
  color: var(--fg-secondary);
  font-family: var(--font-sans);
  font-size: 12px;
  cursor: pointer;
  transition: border-color 120ms ease;
}
.loom-theme-toggle:hover { border-color: var(--border-strong); }
.loom-theme-knob {
  width: 18px; height: 18px;
  border-radius: 50%;
  background: var(--fg-primary);
  transition: background-color 180ms ease;
  display: block;
  position: relative;
  overflow: hidden;
}
.loom-theme-knob.is-dark { background: var(--accent); }
.loom-theme-knob::after {
  content: "";
  position: absolute;
  inset: 2px 2px 2px 8px;
  border-radius: 50%;
  background: var(--bg-page);
  transition: inset 180ms ease;
}
.loom-theme-knob.is-dark::after { inset: 2px 8px 2px 2px; }

.loom-shell {
  display: grid;
  grid-template-columns: var(--col-left) 1fr var(--col-right);
  flex: 1;
  min-height: 0;
  overflow: hidden;
}
.loom-shell.no-left  { grid-template-columns: 1fr var(--col-right); }
.loom-shell.no-right { grid-template-columns: var(--col-left) 1fr; }
.loom-shell.no-left.no-right { grid-template-columns: 1fr; }

.loom-sidebar {
  border-right: 1px solid var(--border-hair);
  overflow-y: auto;
  font-family: var(--font-sans);
  font-size: 13px;
}
.loom-sidebar-inner {
  padding: 28px 12px 28px 20px;
  display: flex;
  flex-direction: column;
  gap: 24px;
}
.loom-sidebar-heading {
  font-size: 11px;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  color: var(--fg-tertiary);
  padding: 0 8px 8px;
  font-weight: 500;
}
.loom-sidebar-list { list-style: none; margin: 0; padding: 0; }
.loom-sidebar-list li { position: relative; }
.loom-sidebar-item {
  display: flex;
  align-items: center;
  position: relative;
  padding: 5px 10px 5px 12px;
  border-radius: 4px;
  color: var(--fg-secondary);
  transition: background-color 120ms ease, color 120ms ease;
  line-height: 1.4;
}
.loom-sidebar-item:hover { color: var(--fg-primary); background: var(--border-soft); }
.loom-sidebar-rail {
  position: absolute;
  left: 0;
  top: 6px; bottom: 6px;
  width: 2px;
  background: transparent;
  border-radius: 1px;
  transition: background-color 120ms ease;
}
.loom-sidebar-list li.is-active > .loom-sidebar-item {
  color: var(--fg-primary);
  background: var(--accent-soft);
  font-weight: 500;
}
.loom-sidebar-list li.is-active > .loom-sidebar-item .loom-sidebar-rail { background: var(--accent); }
.loom-sidebar-num {
  font-variant-numeric: tabular-nums;
  color: var(--fg-tertiary);
  margin-right: 10px;
  font-size: 12px;
  min-width: 12px;
}
.loom-sidebar-sublist {
  list-style: none;
  margin: 2px 0 6px 16px;
  padding: 0 0 0 18px;
  border-left: 1px solid var(--border-hair);
}
.loom-sidebar-sublist li a {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 3px 8px;
  color: var(--fg-tertiary);
  font-size: 12.5px;
  border-radius: 3px;
  transition: color 120ms ease;
}
.loom-sidebar-sublist li a:hover { color: var(--fg-primary); }
.loom-sidebar-sublist li.is-active a { color: var(--fg-primary); }
.loom-sublist-dot {
  width: 4px; height: 4px;
  border-radius: 50%;
  background: var(--fg-tertiary);
  flex-shrink: 0;
  transition: background-color 120ms ease;
}
.loom-sidebar-sublist li.is-active .loom-sublist-dot { background: var(--accent); width: 6px; height: 2px; border-radius: 1px; }
.loom-sidebar-footer {
  margin-top: auto;
  padding: 16px 10px 0;
  border-top: 1px solid var(--border-hair);
}
.loom-sidebar-kicker { font-size: 11px; color: var(--fg-tertiary); font-variant-numeric: tabular-nums; }

.loom-main {
  overflow-y: auto;
  padding: 56px 48px 120px;
  display: flex;
  justify-content: center;
}
.loom-prose {
  width: 100%;
  max-width: var(--measure);
  font-size: 1.0625rem;
  line-height: 1.7;
  color: var(--fg-primary);
}
.loom-main.is-wide .loom-prose { max-width: var(--measure-wide); }

.loom-breadcrumbs {
  font-family: var(--font-sans);
  font-size: 12.5px;
  color: var(--fg-tertiary);
  display: flex;
  align-items: center;
  gap: 6px;
  margin-bottom: 28px;
}
.loom-breadcrumbs .is-current { color: var(--fg-secondary); }
.loom-crumb-sep { opacity: 0.5; }

.loom-h1 {
  font-family: var(--font-serif);
  font-weight: 500;
  font-size: 2.25rem;
  line-height: 1.15;
  letter-spacing: -0.012em;
  margin: 0 0 18px;
  color: var(--fg-primary);
}
.loom-deck {
  font-family: var(--font-serif);
  font-style: italic;
  font-weight: 400;
  font-size: 1.125rem;
  line-height: 1.55;
  color: var(--fg-secondary);
  margin: 0 0 20px;
  max-width: 60ch;
  text-wrap: pretty;
}
.loom-meta {
  font-family: var(--font-sans);
  font-size: 0.8125rem;
  color: var(--fg-tertiary);
  font-variant-numeric: tabular-nums;
}
.loom-rule { height: 1px; background: var(--border-hair); margin: 40px 0 8px; }

.loom-h2 {
  font-family: var(--font-serif);
  font-weight: 500;
  font-size: 1.55rem;
  letter-spacing: -0.008em;
  margin: 3em 0 0.6em;
  color: var(--fg-primary);
  scroll-margin-top: 80px;
}
.loom-h3 {
  font-family: var(--font-serif);
  font-weight: 600;
  font-size: 1.18rem;
  margin: 2em 0 0.5em;
  color: var(--fg-primary);
  scroll-margin-top: 80px;
}

.loom-prose p { margin: 0 0 1.1em; text-wrap: pretty; }
.loom-prose ul { margin: 0 0 1.2em; padding-left: 1.3em; }
.loom-prose ul li { margin-bottom: 0.4em; }
.loom-prose ul li::marker { color: var(--fg-tertiary); }
.loom-prose a {
  color: var(--fg-primary);
  border-bottom: 1px solid var(--accent-ring);
  padding-bottom: 1px;
  transition: border-color 120ms ease, color 120ms ease;
}
.loom-prose a:hover { color: var(--accent); border-color: var(--accent); }

.loom-prose code, code {
  font-family: var(--font-mono);
  font-size: 0.9375em;
  background: var(--bg-inline);
  padding: 0.5px 5px;
  border-radius: 2px;
  font-feature-settings: "tnum";
  color: var(--fg-primary);
  letter-spacing: -0.005em;
}

.loom-code {
  margin: 1.6em 0;
  background: var(--bg-code);
  border: 1px solid var(--border-hair);
  border-radius: 5px;
  overflow: hidden;
  font-family: var(--font-mono);
}
.loom-code-head {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 8px 12px;
  border-bottom: 1px solid var(--border-hair);
  font-family: var(--font-sans);
  font-size: 11.5px;
  color: var(--fg-tertiary);
}
.loom-code-lang {
  color: var(--fg-secondary);
  letter-spacing: 0.04em;
  text-transform: lowercase;
  font-variant: small-caps;
  font-weight: 500;
}
.loom-code-path { color: var(--fg-tertiary); font-family: var(--font-mono); font-size: 11px; opacity: 0.85; flex: 1; }
.loom-code pre { margin: 0; padding: 14px 16px; overflow-x: auto; font-size: 0.9rem; line-height: 1.55; color: var(--fg-primary); white-space: pre; }
.loom-code pre code { font-size: 1em; background: transparent; padding: 0; border-radius: 0; }
.loom-anchor { color: var(--accent); border-bottom: 1px solid var(--accent-ring); }
.loom-anchor:hover { border-color: var(--accent); }

.loom-callout {
  margin: 1.6em 0;
  background: var(--bg-callout);
  border: 1px solid var(--border-hair);
  border-radius: 5px;
  padding: 16px 20px 14px;
}
.loom-callout-label {
  font-family: var(--font-sans);
  font-size: 11.5px;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: var(--accent);
  font-weight: 500;
  margin-bottom: 6px;
}
.loom-callout p { margin: 0; color: var(--fg-primary); }

.loom-blockquote {
  margin: 1.6em 0;
  padding: 2px 0 2px 24px;
  border-left: 1px solid var(--border-strong);
  font-style: italic;
  color: var(--fg-secondary);
  font-size: 1.0625rem;
  line-height: 1.65;
  max-width: 62ch;
}
.loom-prose blockquote, .loom-callout blockquote {
  margin: 0.6em 0;
  padding: 2px 0 2px 16px;
  border-left: 2px solid var(--border-strong);
  color: var(--fg-secondary);
  font-style: italic;
}
.loom-callout blockquote { margin: 0 }
.loom-callout blockquote p { margin: 0 }

.loom-table {
  width: 100%;
  margin: 1.6em 0;
  font-family: var(--font-sans);
  font-size: 0.9375rem;
  border-collapse: collapse;
  font-variant-numeric: tabular-nums;
}
.loom-table thead th {
  text-align: left;
  font-weight: 500;
  color: var(--fg-secondary);
  padding: 10px 16px 10px 0;
  border-bottom: 1px solid var(--border-strong);
  font-size: 0.8125rem;
  letter-spacing: 0.04em;
  text-transform: uppercase;
}
.loom-table tbody td { padding: 10px 16px 10px 0; border-bottom: 1px solid var(--border-hair); color: var(--fg-primary); }
.loom-table tbody tr:last-child td { border-bottom: none; }

.loom-pager {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 16px;
  margin-top: 56px;
  padding-top: 28px;
  border-top: 1px solid var(--border-hair);
  font-family: var(--font-sans);
}
.loom-pager-item {
  display: flex;
  flex-direction: column;
  gap: 4px;
  padding: 14px 16px;
  border: 1px solid var(--border-hair);
  border-radius: 5px;
  transition: border-color 120ms ease;
}
.loom-pager-item:hover { border-color: var(--border-strong); }
.loom-pager-next { text-align: right; align-items: flex-end; }
.loom-pager-kicker { font-size: 11.5px; color: var(--fg-tertiary); letter-spacing: 0.04em; text-transform: uppercase; }
.loom-pager-title { font-size: 14px; color: var(--fg-primary); font-weight: 500; }

.loom-toc {
  border-left: 1px solid var(--border-hair);
  padding: 60px 24px 28px 28px;
  overflow-y: auto;
  font-family: var(--font-sans);
  font-size: 12.5px;
}
.loom-toc-heading {
  font-size: 11px;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  color: var(--fg-tertiary);
  padding-bottom: 12px;
  font-weight: 500;
}
.loom-toc-list { list-style: none; margin: 0; padding: 0; }
.loom-toc-list li a {
  display: flex;
  align-items: center;
  position: relative;
  padding: 5px 0 5px 12px;
  color: var(--fg-secondary);
  transition: color 120ms ease;
  line-height: 1.4;
}
.loom-toc-list li a:hover { color: var(--fg-primary); }
.loom-toc-sub a { padding-left: 24px; color: var(--fg-tertiary); }
.loom-toc-rail {
  position: absolute;
  left: 0;
  top: 8px; bottom: 8px;
  width: 2px;
  background: transparent;
  border-radius: 1px;
  transition: background-color 120ms ease;
}
.loom-toc-list li.is-active a { color: var(--fg-primary); }
.loom-toc-list li.is-active .loom-toc-rail { background: var(--accent); }
.loom-toc-footer {
  margin-top: 32px;
  padding-top: 16px;
  border-top: 1px solid var(--border-hair);
  display: flex;
  flex-direction: column;
  gap: 6px;
  font-size: 12px;
  color: var(--fg-tertiary);
}
.loom-toc-footer a { color: var(--fg-tertiary); transition: color 120ms ease; }
.loom-toc-footer a:hover { color: var(--fg-primary); }

.loom-scrim {
  position: absolute;
  inset: 0;
  background: rgba(31, 28, 22, 0.35);
  backdrop-filter: blur(4px);
  -webkit-backdrop-filter: blur(4px);
  display: flex;
  align-items: flex-start;
  justify-content: center;
  padding-top: 13%;
  z-index: 100;
  animation: loom-fade 140ms ease-out;
}
.loom-theme-dark .loom-scrim { background: rgba(0, 0, 0, 0.55); }
.loom-scrim-quiet { background: rgba(31, 28, 22, 0.18); backdrop-filter: blur(2px); }
.loom-theme-dark .loom-scrim-quiet { background: rgba(0, 0, 0, 0.35); }
@keyframes loom-fade { from { opacity: 0; } to { opacity: 1; } }
@keyframes loom-rise { from { transform: translateY(6px); opacity: 0; } to { transform: translateY(0); opacity: 1; } }

.loom-modal {
  width: min(560px, 86%);
  background: var(--bg-page);
  border: 1px solid var(--border-hair);
  border-radius: 8px;
  box-shadow: var(--shadow-modal);
  overflow: hidden;
  display: flex;
  flex-direction: column;
  max-height: 62vh;
  font-family: var(--font-sans);
  animation: loom-rise 180ms ease-out;
}
.loom-modal-header { padding: 20px 24px 14px; border-bottom: 1px solid var(--border-hair); }
.loom-modal-title {
  font-family: var(--font-serif);
  font-style: italic;
  font-weight: 400;
  font-size: 14px;
  color: var(--fg-tertiary);
  margin-bottom: 6px;
}
.loom-modal-input {
  width: 100%;
  background: transparent;
  border: none;
  outline: none;
  font-family: var(--font-sans);
  font-size: 18px;
  color: var(--fg-primary);
  padding: 2px 0;
}
.loom-modal-input::placeholder { color: var(--fg-tertiary); }
.loom-modal-body { padding: 12px; overflow-y: auto; }
.loom-result-group { padding: 6px 0 10px; }
.loom-result-heading {
  font-size: 10.5px;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: var(--fg-tertiary);
  padding: 6px 12px;
  font-weight: 500;
}
.loom-result-item {
  display: flex;
  align-items: baseline;
  justify-content: space-between;
  gap: 16px;
  padding: 8px 12px;
  border-radius: 4px;
  color: var(--fg-secondary);
  font-size: 13.5px;
  cursor: pointer;
}
.loom-result-item:hover, .loom-result-item.is-hover { background: var(--accent-soft); color: var(--fg-primary); }
.loom-result-title { font-weight: 500; }
.loom-result-path { font-family: var(--font-mono); font-size: 11.5px; color: var(--fg-tertiary); white-space: nowrap; }
.loom-modal-footer {
  display: flex;
  gap: 18px;
  padding: 10px 20px;
  border-top: 1px solid var(--border-hair);
  font-size: 11.5px;
  color: var(--fg-tertiary);
}
.loom-modal-footer kbd, .loom-shortcuts kbd {
  font-family: var(--font-sans);
  font-size: 10.5px;
  background: var(--bg-surface);
  border: 1px solid var(--border-hair);
  padding: 1px 5px;
  border-radius: 3px;
  color: var(--fg-secondary);
}

.loom-shortcuts {
  width: 320px;
  background: var(--bg-page);
  border: 1px solid var(--border-hair);
  border-radius: 6px;
  padding: 22px 24px;
