const NavigateInternal = Command.define(
  'NavigateInternal',
  { url: S.String },
  CompletedNavigation,
)(({ url }) => Navigation.pushUrl(url).pipe(Effect.as(CompletedNavigation())))

const NavigateExternal = Command.define(
  'NavigateExternal',
  { href: S.String },
  CompletedNavigation,
)(({ href }) => Navigation.load(href).pipe(Effect.as(CompletedNavigation())))

const CopyToClipboard = Command.define(
  'CopyToClipboard',
  { text: S.String },
  CompletedNavigation,
)(({ text }) =>
  Effect.promise(() => navigator.clipboard.writeText(text)).pipe(Effect.as(CompletedNavigation())),
)

const init: Runtime.RoutingApplicationInit<Model, Message> = (url) => [
  { route: routeForPath(url.pathname), theme: 'dark', navClosed: false, tocClosed: false },
  [],
]

const update = (
  model: Model,
  message: Message,
): readonly [Model, ReadonlyArray<Command.Command<Message>>] =>
  Match.value(message).pipe(
    Match.withReturnType<readonly [Model, ReadonlyArray<Command.Command<Message>>]>(),
    Match.tagsExhaustive({
      ChangedUrl: ({ route }) => [{ ...model, route, navClosed: false }, []],
      ClickedLink: ({ request }) =>
        Match.value(request).pipe(
          Match.withReturnType<readonly [Model, ReadonlyArray<Command.Command<Message>>]>(),
          Match.tag('Internal', ({ url }) => [model, [NavigateInternal({ url: Url.toString(url) })]]),
          Match.tag('External', ({ href }) => [model, [NavigateExternal({ href })]]),
          Match.exhaustive,
        ),
      CompletedNavigation: () => [model, []],
      ToggledTheme: () => [{ ...model, theme: model.theme === 'dark' ? 'light' : 'dark' }, []],
      ToggledNav: () => [{ ...model, navClosed: !model.navClosed }, []],
      ToggledToc: () => [{ ...model, tocClosed: !model.tocClosed }, []],
      Copy: ({ text }) => [model, [CopyToClipboard({ text })]],
    }),
  )

const shellClass = (model: Model): string =>
  ['loom-shell', model.navClosed ? 'no-left' : '', model.tocClosed ? 'no-right' : '']
    .filter(Boolean)
    .join(' ')

const docsShell = (model: Model, page: WovenPage): Html =>
  h.div(
    [h.Class(shellClass(model))],
    [
      ...(model.navClosed ? [] : [sidebarView(page.slug)]),
      mainView(model, page),
      ...(model.tocClosed ? [] : [outlineView(page)]),
    ],
  )

const view = (model: Model): Document =>
  Match.value(model.route).pipe(
    Match.withReturnType<Document>(),
    Match.tag('Landing', () => ({
      title: 'Loom — literate programming',
      body: appFrame(model, landingView()),
    })),
    Match.tag('Docs', ({ slug }) => {
      const page = docsPage(slug)
      return { title: `${page.title} · Loom`, body: appFrame(model, docsShell(model, page)) }
    }),
    Match.exhaustive,
  )

const application = Runtime.makeApplication({
  Model,
  init,
  update,
  view,
  routing: {
    onUrlChange: (url: Url.Url) => ChangedUrl({ route: routeForPath(url.pathname) }),
    onUrlRequest: (request: Navigation.UrlRequest) => ClickedLink({ request }),
  },
  container: document.getElementById('root')!,
})

Runtime.run(application)

export const Model = S.Struct({
  route: RouteSchema,
  theme: S.Literals(['light', 'dark']),
  navClosed: S.Boolean,
  tocClosed: S.Boolean,
})
export type Model = typeof Model.Type

export const ChangedUrl = m('ChangedUrl', { route: RouteSchema })
export const ClickedLink = m('ClickedLink', { request: Navigation.UrlRequest })
export const CompletedNavigation = m('CompletedNavigation')
export const ToggledTheme = m('ToggledTheme')
export const ToggledNav = m('ToggledNav')
export const ToggledToc = m('ToggledToc')
export const Copy = m('Copy', { text: S.String })

export const Message = S.Union([
  ChangedUrl,
  ClickedLink,
  CompletedNavigation,
  ToggledTheme,
  ToggledNav,
  ToggledToc,
  Copy,
])
export type Message = typeof Message.Type

export const h = html<Message>()

const stripOrder = (segment: string): string => segment.replace(/^\d+-/, '')

export const pathForSlug = (slug: string): string =>
  `/${pipe(slug.split('/'), Array.map(stripOrder), Array.join('/'))}`

export const firstSlug = pipe(
  Array.flatMap(site.nav, (part) => part.chapters),
  Array.head,
  Option.map((chapter) => chapter.slug),
  Option.getOrElse(() => ''),
)

const pathIndex = new Map(
  Array.map(site.pages, (page) => [pathForSlug(page.slug), page.slug] as const),
)

const slugForPath = (pathname: string): string =>
  Option.getOrElse(Option.fromNullishOr(pathIndex.get(pathname)), () => firstSlug)

export const routeForPath = (pathname: string): Route =>
  pathname === '/' ? { _tag: 'Landing' } : { _tag: 'Docs', slug: slugForPath(pathname) }

const bumpMinor = (text: string): string =>
  text.replace(
    /("version": ")(\d+)\.(\d+)\.\d+(")/,
    (_m, pre, major, minor, post) => `${pre}${major}.${Number(minor) + 1}.0${post}`,
  )

const before = readFileSync(manifest, 'utf8')
const after = bumpMinor(before)
if (after === before) throw new Error('no "version" to bump in the manifest chapter')
writeFileSync(manifest, after)

