const here = dirname(fileURLToPath(import.meta.url))
const requireFromHere = createRequire(import.meta.url)

const nodeBuiltins = [
  ...builtinModules,
  ...builtinModules.map((m) => `node:${m}`),
]

const umd2esm = {
  name: 'umd2esm',
  enforce: 'pre' as const,
  resolveId(source: string, importer: string | undefined) {
    if (/^(vscode-.*-languageservice|jsonc-parser)/.test(source)) {
      const fromDir = importer ? dirname(importer) : here
      const resolved = requireFromHere.resolve(source, { paths: [fromDir] })
      return resolved.replace(/\/umd\//, '/esm/').replace(/\\umd\\/g, '\\esm\\')
    }
    return null
  },
}

export default defineConfig({
  plugins: [umd2esm],
  resolve: {
    conditions: ['node'],
    mainFields: ['main', 'module'],
    alias: {
      'vscode-uri': requireFromHere
        .resolve('vscode-uri')
        .replace(/esm[\\/]index\.mjs$/, 'umd/index.js'),
    },
  },
  build: {
    target: 'node20',
    outDir: 'dist',
    emptyOutDir: true,
    sourcemap: true,
    minify: false,
    lib: {
      entry: {
        client: resolve(here, 'src/vscode-extension.ts'),
        server: resolve(here, '../loom-lang/src/index.ts'),
      },
      formats: ['cjs'],
    },
    rollupOptions: {
      external: ['vscode', ...nodeBuiltins],
      output: { entryFileNames: '[name].js' },
    },
  },
})

export async function activate(context: vscode.ExtensionContext) {
  const serverModule = vscode.Uri.joinPath(
    context.extensionUri,
    'dist',
    'server.js',
  )
  const serverOptions: ServerOptions = {
    run: {
      module: serverModule.fsPath,
      transport: TransportKind.ipc,
      options: { execArgv: [] as string[] },
    },
    debug: {
      module: serverModule.fsPath,
      transport: TransportKind.ipc,
      options: { execArgv: ['--nolazy', '--inspect=6009'] },
    },
  }

  const tsdk = path.join(
    vscode.env.appRoot,
    'extensions',
    'node_modules',
    'typescript',
    'lib',
  )

  const clientOptions: LanguageClientOptions = {
    documentSelector: [{ language: 'loom' }],
    initializationOptions: { typescript: { tsdk } },
  }

  client = new LanguageClient(
    'loom-language-server',
    'Loom Language Server',
    serverOptions,
    clientOptions,
  )
  await client.start()

  activateAutoInsertion('loom', client)

  const labsInfo = createLabsInfo(serverProtocol)
  labsInfo.addLanguageClient(client)
  return labsInfo.extensionExports
}

export function deactivate(): Thenable<any> | undefined {
  return client?.stop()
}

const loadService = (
  id: string,
  root: string,
): Effect.Effect<Option.Option<LanguageService>> =>
  Effect.tryPromise(async () => {
    const from = join(storeDir(dirname(root)), 'index.js')
    const entry = createRequire(from).resolve(servicePackage(id))
    const loaded = (await import(pathToFileURL(entry).href)) as {
      readonly default?: unknown
    }
    return loaded.default
  }).pipe(
    Effect.flatMap((exported) =>
      isLanguageService(exported) && exported.id === id
        ? Effect.succeed(Option.some(exported))
        : Effect.logWarning(
            `${servicePackage(id)} does not export a language service for "${id}"`,
          ).pipe(Effect.as(Option.none<LanguageService>())),
    ),
    Effect.catchCause(() =>
      Effect.logWarning(
        `language "${id}" is activated but ${servicePackage(id)} is not installed — run \`loom add ${id}\``,
      ).pipe(Effect.as(Option.none<LanguageService>())),
    ),
  )

const loomOverrides = (
  options: CompilerOptions,
): CompilerOptions => ({
  ...options,
  noEmit: true,
  allowImportingTsExtensions: true,
})

const baselineOptions = (ts: TypeScript): CompilerOptions =>
  loomOverrides({
    target: ts.ScriptTarget.ES2022,
    module: ts.ModuleKind.ESNext,
    moduleResolution: ts.ModuleResolutionKind.Bundler,
    strict: true,
    skipLibCheck: true,
  })

const consumerOptions = (ts: TypeScript, loomPath: string): CompilerOptions => {
  const found = ts.findConfigFile(dirname(loomPath), ts.sys.fileExists, 'tsconfig.json')
  if (found === undefined) return baselineOptions(ts)
  const read = ts.readConfigFile(found, ts.sys.readFile)
  const parsed = ts.parseJsonConfigFileContent(read.config ?? {}, ts.sys, dirname(found))
  return loomOverrides(parsed.options)
}

export interface ProductTarget {
  readonly program: ProductProgram
  readonly fileName: string
  readonly roots: ReadonlyArray<ComposedFile>
}

const tsExtension: ReadonlyMap<string, string> = new Map([
  ['typescript', '.ts'],
  ['tsx', '.tsx'],
  ['javascript', '.js'],
  ['jsx', '.jsx'],
])

export const productTarget = (
  decoded: readonly [URI, string] | undefined,
  languageId: string,
  text: string,
  programFor: (loomPath: string) => ProductProgram,
  rootsFor: (loomPath: string) => ReadonlyArray<ComposedFile>,
): ProductTarget | undefined => {
  const extension = tsExtension.get(languageId)
  if (decoded === undefined || extension === undefined) return undefined
  const [loomUri, rootId] = decoded
  const loomPath = loomUri.fsPath
  const composed = rootsFor(loomPath)
  const sink = Array.findFirst(
    composed,
    (file) => file.loomPath === loomPath && file.rootId === rootId,
  )
  const edited: ComposedFile = Option.getOrElse(sink, () => ({
    path: `${loomPath}.${rootId}${extension}`,
    content: text,
    loomPath,
    rootId,
    heading: {
      path: loomPath,
      range: { start: { line: 0, character: 0 }, end: { line: 0, character: 0 } },
    },
  }))
  const roots = Option.match(sink, {
    onNone: () => Array.append(composed, edited),
    onSome: () => composed,
  })
  const program = programFor(loomPath)
  program.sync(
    Array.map(roots, (file) => ({
      path: file.path,
      text: file === edited ? text : file.content,
    })),
  )
  return { program, fileName: edited.path, roots }
}

const productPlugin = (
  ts: TypeScript,
  composition: CompositionApi,
): LanguageServicePlugin => ({
  name: 'loom-typescript-product',
  capabilities: {
    diagnosticProvider: { interFileDependencies: false, workspaceDiagnostics: false },
    hoverProvider: true,
    completionProvider: { triggerCharacters: ['.'] },
    definitionProvider: true,
    referencesProvider: true,
    renameProvider: {},
    codeActionProvider: {
      codeActionKinds: ['quickfix', 'refactor', 'source.organizeImports'],
    },
  },
  create: (context) => {
    const programs = new Map<string, ProductProgram>()
    const programFor = (loomPath: string): ProductProgram => {
      const existing = programs.get(loomPath)
      if (existing !== undefined) return existing
      const program = createProductProgram(ts, consumerOptions(ts, loomPath))
      programs.set(loomPath, program)
      return program
    }
    const targetOf = (
      uri: string,
      languageId: string,
      text: string,
    ): ProductTarget | undefined =>
      productTarget(
        context.decodeEmbeddedDocumentUri(URI.parse(uri)),
        languageId,
        text,
        programFor,
        composition.rootsFor,
      )

    const embeddedUriOf = (
      roots: ReadonlyArray<ComposedFile>,
      uri: string,
    ): string =>
      Option.match(
        Array.findFirst(roots, (file) => file.path === URI.parse(uri).fsPath),
        {
          onNone: () => uri,
          onSome: (file) =>
            context
              .encodeEmbeddedDocumentUri(URI.file(file.loomPath), file.rootId)
              .toString(),
        },
      )

    const remapEdit = (
      roots: ReadonlyArray<ComposedFile>,
      edit: WorkspaceEdit,
    ): WorkspaceEdit => ({
      ...edit,
      changes:
        edit.changes === undefined
          ? undefined
          : Object.fromEntries(
              Object.entries(edit.changes).map(([uri, edits]) => [
                embeddedUriOf(roots, uri),
                edits,
              ]),
            ),
      documentChanges: edit.documentChanges?.map((change) =>
        'textDocument' in change
          ? {
              ...change,
              textDocument: {
                ...change.textDocument,
                uri: embeddedUriOf(roots, change.textDocument.uri),
              },
            }
          : change,
      ),
    })

    const remapAction = (
      roots: ReadonlyArray<ComposedFile>,
      action: CodeAction,
    ): CodeAction =>
      action.edit === undefined
        ? action
        : { ...action, edit: remapEdit(roots, action.edit) }

    const atFileStart = (range: Range): boolean =>
      range.start.line === 0 &&
      range.start.character === 0 &&
      range.end.line === 0 &&
      range.end.character === 0

    const remapDefinition = (
      roots: ReadonlyArray<ComposedFile>,
      link: LocationLink,
    ): LocationLink =>
      pipe(
        Array.findFirst(roots, (file) => file.path === URI.parse(link.targetUri).fsPath),
        Option.filter(() => atFileStart(link.targetRange)),
        Option.match({
          onNone: () => ({ ...link, targetUri: embeddedUriOf(roots, link.targetUri) }),
          onSome: (file) => ({
            ...link,
            targetUri: URI.file(file.heading.path).toString(),
            targetRange: file.heading.range,
            targetSelectionRange: file.heading.range,
          }),
        }),
      )

    return {
      provideDiagnostics: (document) => {
        const target = targetOf(document.uri, document.languageId, document.getText())
        return target === undefined
          ? undefined
          : target.program.diagnostics(target.fileName)
      },
      provideHover: (document, position) => {
        const target = targetOf(document.uri, document.languageId, document.getText())
        return target === undefined
          ? undefined
          : target.program.hover(target.fileName, position)
      },
      provideCompletionItems: (document, position) => {
        const target = targetOf(document.uri, document.languageId, document.getText())
        return target === undefined
          ? undefined
          : target.program.completions(target.fileName, position)
      },
      provideDefinition: (document, position) => {
        const target = targetOf(document.uri, document.languageId, document.getText())
        return target === undefined
          ? undefined
          : target.program
              .definition(target.fileName, position)
              .then((links) =>
                links?.map((link) => remapDefinition(target.roots, link)),
              )
      },
      provideReferences: (document, position) => {
        const target = targetOf(document.uri, document.languageId, document.getText())
        return target === undefined
          ? undefined
          : target.program
              .references(target.fileName, position)
              .then((locations) =>
                locations?.map((location) => ({
                  ...location,
                  uri: embeddedUriOf(target.roots, location.uri),
                })),
              )
      },
      provideRenameEdits: (document, position, newName) => {
        const target = targetOf(document.uri, document.languageId, document.getText())
        return target === undefined
          ? undefined
          : target.program
              .rename(target.fileName, position, newName)
              .then((edit) =>
                edit === undefined ? edit : remapEdit(target.roots, edit),
              )
      },
      provideCodeActions: (document, range, context) => {
        const target = targetOf(document.uri, document.languageId, document.getText())
        return target === undefined
          ? undefined
          : target.program
              .codeActions(target.fileName, range, context)
              .then((actions) =>
                actions === undefined
                  ? undefined
                  : Promise.all(
                      actions.map((action) =>
                        (action.edit === undefined
                          ? target.program.resolveCodeAction(action)
                          : Promise.resolve(action)
                        ).then((resolved) => remapAction(target.roots, resolved)),
                      ),
                    ),
              )
      },
      dispose: () => programs.forEach((program) => program.dispose()),
    }
  },
})

export const TypescriptService = defineLanguageService({
  id: 'typescript',
  displayName: 'TypeScript',
  extensions: ['.ts', '.tsx'],
  plugins: () =>
    Effect.gen(function* () {
      const ts = yield* TypescriptSdk
      const composition = yield* Composition
      return [productPlugin(ts, composition)]
    }),
})

export default TypescriptService

const productLanguage = (
  ts: TypeScript,
  roots: ReadonlyMap<string, IScriptSnapshot>,
): Language<URI> => {
  const language = createLanguage<URI>(
    [{ getLanguageId: (uri: URI) => resolveFileLanguageId(uri.path) }],
    createUriMap(ts.sys.useCaseSensitiveFileNames),
    (uri, includeFsFiles) => {
      const fileName = uri.fsPath
      const root = roots.get(fileName)
      if (root) {
        language.scripts.set(uri, root)
        return
      }
      if (!includeFsFiles) return
      const text = ts.sys.fileExists(fileName)
        ? ts.sys.readFile(fileName)
        : undefined
      if (text !== undefined) {
        language.scripts.set(uri, ts.ScriptSnapshot.fromString(text))
      } else {
        language.scripts.delete(uri)
      }
    },
  )
  return language
}

export const createProductProgram = (
  ts: TypeScript,
  compilerOptions: CompilerOptions,
): ProductProgram => {
  const roots = new Map<string, IScriptSnapshot>()
  let projectVersion = 0
  const language = productLanguage(ts, roots)
  const asUri = (fileName: string): URI => URI.file(fileName)

  const projectHost = {
    getCurrentDirectory: () => process.cwd(),
    getCompilationSettings: () => compilerOptions,
    getProjectVersion: () => projectVersion.toString(),
    getScriptFileNames: () => [...roots.keys()],
  }

  const env: LanguageServiceEnvironment = {
    workspaceFolders: [URI.file(process.cwd())],
  }

  const service = createLanguageService(
    language,
    createTypescriptServices(ts),
    env,
    {
      typescript: {
        configFileName: undefined,
        sys: ts.sys,
        uriConverter: { asFileName: (uri: URI) => uri.fsPath, asUri },
        ...createLanguageServiceHost(ts, ts.sys, language, asUri, projectHost),
      },
    },
  )

  const unchanged = (path: string, text: string): boolean =>
    pipe(
      Option.fromNullishOr(roots.get(path)),
      Option.match({
        onNone: () => false,
        onSome: (snapshot) => snapshot.getText(0, snapshot.getLength()) === text,
      }),
    )

  const sync = (
    files: ReadonlyArray<{ readonly path: string; readonly text: string }>,
  ): void => {
    const present = new Set(Array.map(files, (file) => file.path))
    const stale = Array.filter(
      Array.fromIterable(roots.keys()),
      (path) => !present.has(path),
    )
    const fresh = Array.filter(files, (file) => !unchanged(file.path, file.text))
    if (stale.length === 0 && fresh.length === 0) return
    stale.forEach((path) => {
      roots.delete(path)
      language.scripts.delete(asUri(path))
    })
    fresh.forEach((file) => {
      const snapshot = ts.ScriptSnapshot.fromString(file.text)
      roots.set(file.path, snapshot)
      language.scripts.set(asUri(file.path), snapshot)
    })
    projectVersion++
  }

  return {
    sync,
    diagnostics: (fileName) => service.getDiagnostics(asUri(fileName)),
    hover: (fileName, position) => service.getHover(asUri(fileName), position),
    completions: (fileName, position) =>
      service.getCompletionItems(asUri(fileName), position),
    definition: (fileName, position) =>
      service.getDefinition(asUri(fileName), position),
    references: (fileName, position) =>
      service.getReferences(asUri(fileName), position, {
        includeDeclaration: true,
      }),
    rename: (fileName, position, newName) =>
      service.getRenameEdits(asUri(fileName), position, newName),
    codeActions: (fileName, range, context) =>
      service.getCodeActions(asUri(fileName), range, context),
    resolveCodeAction: (action) => service.resolveCodeAction(action),
    dispose: () => service.dispose(),
  }
}

