export type MalformedConstruct =
  | 'specifier'
  | 'path'
  | 'warpName'
  | 'anchorName'

export type EmptyConstruct =
  | MalformedConstruct
  | 'warpAnnotation'
  | 'warpDefault'

export type LoomFault = Data.TaggedEnum<{
  UnclosedDelimiter: { readonly expected: string }
  EmptyLabel: { readonly construct: EmptyConstruct }
  MalformedLabel: {
    readonly construct: MalformedConstruct
    readonly value: string
  }
  MissingWarpValue: { readonly name: string }
  UnresolvedAnchor: { readonly name: string }
  AmbiguousAnchor: { readonly name: string; readonly count: number }
  CrossLanguageAnchor: {
    readonly name: string
    readonly host: string
    readonly found: string
  }
  UnresolvedTocEntry: { readonly title: string }
}>

type Note = { readonly severity: Severity; readonly message: string }

const error = (message: string): Note => ({ severity: 'error', message })

const cap = (text: string): string =>
  text.charAt(0).toUpperCase() + text.slice(1)

const noun: Record<EmptyConstruct, string> = {
  specifier: 'specifier label',
  path: 'file path',
  warpName: 'warp name',
  anchorName: 'anchor name',
  warpAnnotation: 'warp annotation',
  warpDefault: 'warp default',
}

const rule: Record<MalformedConstruct, string> = {
  specifier: 'may contain only letters, digits, hyphen, and underscore',
  path: 'may contain only letters, digits, hyphen, underscore, dot, and slash',
  warpName: 'must be a TypeScript identifier',
  anchorName: 'may not contain `]`',
}

export const describe = (fault: LoomFault): Note =>
  Match.value(fault).pipe(
    Match.tag('UnclosedDelimiter', ({ expected }) =>
      error(`expected closing \`${expected}\``),
    ),
    Match.tag('EmptyLabel', ({ construct }) =>
      error(`${cap(noun[construct])} cannot be empty.`),
    ),
    Match.tag('MalformedLabel', ({ construct, value }) =>
      error(`${cap(noun[construct])} ${rule[construct]}; got \`${value}\`.`),
    ),
    Match.tag('MissingWarpValue', ({ name }) =>
      error(`Warp \`${name}\` has no value; a Warp binds a value, as in \`${name} = …\`.`),
    ),
    Match.tag('UnresolvedAnchor', ({ name }) =>
      error(`Unresolved anchor: no section named \`${name}\`.`),
    ),
    Match.tag('AmbiguousAnchor', ({ name, count }) =>
      error(
        `Ambiguous anchor: ${count} sections are named \`${name}\`. A name anchor resolves one local section; rename to disambiguate.`,
      ),
    ),
    Match.tag('CrossLanguageAnchor', ({ name, host, found }) =>
      error(
        `Cross-language transclusion: \`${name}\` is ${found}, but this section composes ${host}. A section composes one language.`,
      ),
    ),
    Match.tag('UnresolvedTocEntry', ({ title }) =>
      error(`Unresolved contents entry: no chapter titled \`${title}\`.`),
    ),
    Match.exhaustive,
  )

const statusOf = (severity: Severity): Health['status'] =>
  severity === 'info' ? 'ok' : severity

export const faulty = (fault: LoomFault, position: Position): Health => {
  const note = describe(fault)
  return {
    status: statusOf(note.severity),
    diagnostics: [{ message: note.message, position, severity: note.severity }],
  }
}

const ignoredSegment = new Set(['node_modules', '.loom', 'dist', '.git'])

const isStorePath = (name: string): boolean =>
  name.split('/').some((segment) => ignoredSegment.has(segment))

export class LoomTangler extends Context.Service<LoomTangler>()('LoomTangler', {
  make: Effect.gen(function* () {
    const compiler = yield* LoomCompiler
    const fs = yield* FileSystem.FileSystem

    const writeFile = (file: TangledFile): Effect.Effect<TangledFile> =>
      fs
        .makeDirectory(dirname(file.path), { recursive: true })
        .pipe(
          Effect.andThen(fs.writeFileString(file.path, file.content)),
          Effect.orDie,
          Effect.as(file),
        )

    const tangleFile = (
      entry: Path,
    ): Effect.Effect<ReadonlyArray<TangledFile>, TangleError> =>
      compiler
        .tangle(entry)
        .pipe(Effect.flatMap((files) => Effect.forEach(files, writeFile)))

    const loomsUnder = (dir: Path): Effect.Effect<ReadonlyArray<Path>> =>
      fs.readDirectory(dir, { recursive: true }).pipe(
        Effect.orDie,
        Effect.map((names) =>
          pipe(
            names,
            Array.filter((name) => name.endsWith('.loom') && !isStorePath(name)),
            Array.map((name) => resolvePath(dir, name)),
          ),
        ),
      )

    const tangle = (
      path: Path,
    ): Effect.Effect<ReadonlyArray<TangledFile>, TangleError> =>
      Effect.gen(function* () {
        const info = yield* fs.stat(path).pipe(Effect.orDie)
        const looms =
          info.type === 'Directory' ? yield* loomsUnder(path) : [path]
        const written = yield* Effect.forEach(looms, tangleFile)
        return written.flat()
      })

    return { tangle }
  }),
}) {
  static readonly layer = Layer.effect(this, this.make).pipe(
    Layer.provide(LoomCompiler.layer),
  )
}

import { Effect, Schema } from 'effect'
import type { IncomingMessage } from 'node:http'
import { FeedbackLog } from './feedback-log'
import { DraftSchema } from './entry'

const bodyJson = (req: IncomingMessage): Effect.Effect<unknown, unknown> =>
  Effect.gen(function* () {
    const raw = yield* Effect.tryPromise({ try: () => bodyText(req), catch: (e) => e })
    return yield* Effect.try({ try: () => JSON.parse(raw) as unknown, catch: (e) => e })
  })

const SeqBody = Schema.Struct({ seq: Schema.Number })
const EditBody = Schema.Struct({ seq: Schema.Number, text: Schema.String })

const captureProgram = (req: IncomingMessage) =>
  Effect.gen(function* () {
    const draft = yield* Schema.decodeUnknownEffect(DraftSchema)(yield* bodyJson(req))
    const log = yield* FeedbackLog
    return yield* log.record(draft)
  })

const feedProgram = Effect.gen(function* () {
  const log = yield* FeedbackLog
  return yield* log.list
})

const resolveProgram = (req: IncomingMessage) =>
  Effect.gen(function* () {
    const { seq } = yield* Schema.decodeUnknownEffect(SeqBody)(yield* bodyJson(req))
    const log = yield* FeedbackLog
    yield* log.resolve(seq)
    return { ok: true, seq }
  })

const discardProgram = (req: IncomingMessage) =>
  Effect.gen(function* () {
    const { seq } = yield* Schema.decodeUnknownEffect(SeqBody)(yield* bodyJson(req))
    const log = yield* FeedbackLog
    yield* log.discard(seq)
    return { ok: true, seq }
  })

const updateProgram = (req: IncomingMessage) =>
  Effect.gen(function* () {
    const { seq, text } = yield* Schema.decodeUnknownEffect(EditBody)(yield* bodyJson(req))
    const log = yield* FeedbackLog
    yield* log.edit(seq, text)
    return { ok: true, seq }
  })

const bodyText = (req: IncomingMessage): Promise<string> => {
  const chunks: Array<Uint8Array> = []
  return new Promise((settle, reject) => {
    req.on('data', (chunk: Uint8Array) => chunks.push(chunk))
    req.on('end', () => settle(Buffer.concat(chunks).toString('utf8')))
    req.on('error', reject)
  })
}

import { Layer, ManagedRuntime, Match } from 'effect'
import { BunServices } from '@effect/platform-bun'
import type { Plugin } from 'vite'
import type { ServerResponse } from 'node:http'
import { readFileSync } from 'node:fs'
import { fileURLToPath } from 'node:url'
import { resolve } from 'node:path'

export const loomAnnotate = (options?: { readonly path?: string }): Plugin => {
  const overlaySource = readFileSync(fileURLToPath(new URL('./overlay.ts', import.meta.url)), 'utf8')
  const overlayModule = new Bun.Transpiler({ loader: 'ts' }).transformSync(overlaySource)
  const runtime = ManagedRuntime.make(FeedbackLog.layer.pipe(Layer.provide(BunServices.layer)))

  const sendJson = (res: ServerResponse, value: unknown): void => {
    res.setHeader('content-type', 'application/json')
    res.end(JSON.stringify(value))
  }
  const sendError = (res: ServerResponse, error: unknown): void => {
    res.statusCode = 400
    res.setHeader('content-type', 'text/plain')
    res.end(String(error))
  }
  const run = (res: ServerResponse, program: Effect.Effect<unknown, unknown, FeedbackLog>): void =>
    void runtime.runPromise(program).then(
      (value) => sendJson(res, value),
      (error) => sendError(res, error),
    )

  return {
    name: 'loom-annotate',
    apply: 'serve',
    configResolved(config) {
      process.env.LOOM_ANNOTATE_LOG = resolve(config.root, options?.path ?? '.loom/feedback.jsonl')
    },
    configureServer(server) {
      server.middlewares.use((req, res, next) => {
        const request = { url: (req.url ?? '').split('?')[0], method: req.method ?? 'GET' }
        Match.value(request).pipe(
          Match.when({ url: '/__annotate/overlay.js', method: 'GET' }, () => {
            res.setHeader('content-type', 'text/javascript')
            res.end(overlayModule)
          }),
          Match.when({ url: '/__annotate/capture', method: 'POST' }, () => run(res, captureProgram(req))),
          Match.when({ url: '/__annotate/feed', method: 'GET' }, () => run(res, feedProgram)),
          Match.when({ url: '/__annotate/resolve', method: 'POST' }, () => run(res, resolveProgram(req))),
          Match.when({ url: '/__annotate/discard', method: 'POST' }, () => run(res, discardProgram(req))),
          Match.when({ url: '/__annotate/update', method: 'POST' }, () => run(res, updateProgram(req))),
          Match.orElse(() => next()),
        )
      })
    },
    transformIndexHtml() {
      return [
        {
          tag: 'script',
          attrs: { type: 'module', src: '/__annotate/overlay.js' },
          injectTo: 'body',
        },
      ]
    },
  }
}

const logPaths = Effect.sync((): ReadonlyArray<string> =>
  Array.fromIterable(new Bun.Glob('**/.loom/feedback.jsonl').scanSync({ dot: true })).filter(
    (path) => !path.includes('node_modules'),
  ),
)

const formatEntry = (entry: Entry): string => {
  const status = (entry.addressed ? 'resolved' : 'open').padEnd(8)
  const lines = [`  #${entry.seq}  ${status}  ${entry.kind}  ·  ${entry.route}`]
  if (entry.kind === 'annotation') {
    lines.push(`      element:  ${entry.label}`)
    lines.push(`      selector: ${entry.selector}`)
  }
  lines.push(`      ${entry.text}`)
  return lines.join('\n')
}

const listProgram = Effect.gen(function* () {
  const fs = yield* FileSystem.FileSystem
  const paths = yield* logPaths
  const logs = yield* Effect.forEach(paths, (path) =>
    readEntries(fs, path).pipe(Effect.map((entries) => ({ path, entries }))),
  )
  const all = Array.flatMap(logs, (log) => log.entries)
  const open = Array.filter(all, (entry) => !entry.addressed).length

  if (all.length === 0) {
    yield* Console.log('No annotations yet.')
    return
  }

  yield* Console.log(`Loom annotations — ${all.length} total, ${open} open`)
  yield* Effect.forEach(logs, (log) =>
    Effect.gen(function* () {
      yield* Console.log(`\n${log.path}`)
      yield* Effect.forEach(log.entries, (entry) => Console.log(formatEntry(entry)))
    }),
  )
})

const changeLog = (
  op: (fs: FileSystem.FileSystem, path: string, seq: number) => Effect.Effect<void, unknown>,
  done: (seq: number, path: string) => string,
  usage: string,
  rest: ReadonlyArray<string>,
): Effect.Effect<void, unknown, FileSystem.FileSystem> =>
  Effect.gen(function* () {
    const fs = yield* FileSystem.FileSystem
    const seq = Number(rest[0])
    if (!Number.isInteger(seq)) {
      yield* Console.error(usage)
      return
    }
    const found = rest[1] ? [rest[1]] : yield* logPaths
    if (found.length !== 1) {
      yield* Console.error(
        found.length === 0
          ? 'No .loom/feedback.jsonl found.'
          : `Several logs — name one:\n  ${found.join('\n  ')}`,
      )
      return
    }
    const path = found[0]!
    yield* op(fs, path, seq)
    yield* Console.log(done(seq, path))
  })

