import {
  type LoomDocument,
  type LoomFrontmatter,
  type LoomHeading,
  type LoomSection,
} from '#ast/LoomAst'
import { type SectionBodyWeft, type TocWeft } from '#ast/Weft'
import {
  type WarpAnchorToken,
